SELECT model_no
FROM inventory
WHERE quantity_on_hand > 10;

SELECT model_no
FROM wire_containers
ORDER BY model_no;

SELECT SUM(quantity_on_hand) AS total_quantity
FROM inventory
WHERE model_no = '0';

SELECT model_no
FROM wire_containers
WHERE quantity = (SELECT MAX(quantity) FROM wire_containers);

SELECT model_no
FROM inventory
WHERE quantity_on_hand < reorder_threshold;
